function solve(points) {
    const MOD = 1e9 + 7;
    const yToXs = new Map();

    for (const [x, y] of points) {
        if (!yToXs.has(y)) {
            yToXs.set(y, new Set());
        }
        yToXs.get(y).add(x);
    }

    const yList = Array.from(yToXs.keys()).filter(y => yToXs.get(y).size >= 2);
    yList.sort((a, b) => a - b);

    let res = 0;
    const n = yList.length;

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const y1 = yList[i];
            const y2 = yList[j];
            const set1 = yToXs.get(y1);
            const set2 = yToXs.get(y2);
            const commonXs = [];

            for (const x of set1) {
                if (set2.has(x)) {
                    commonXs.push(x);
                }
            }

            const m = commonXs.length;
            if (m >= 2) {
                const cnt = m * (m - 1) / 2;
                res = (res + cnt) % MOD;
            }
        }
    }

    return res;
}

